import React from 'react';
import { Card, Button, Divider, List, Typography, Space, Tag } from 'antd';
import { DownloadOutlined, FileZipOutlined, FileTextOutlined, DatabaseOutlined } from '@ant-design/icons';

const { Title, Paragraph, Text } = Typography;

export default function Download() {
  // 定义数据结构，方便维护和渲染
  const downloadSections = [
    {
      title: 'Raw Expression Data',
      description: 'Transcriptome profiling data for Lung Adenocarcinoma and matched normal tissues.',
      files: [
        { name: 'Tumor_test.rar', label: 'Tumor Samples Data', type: 'RAR', icon: <FileZipOutlined /> },
        { name: 'Normal_test.rar', label: 'Normal Samples Data', type: 'RAR', icon: <FileZipOutlined /> },
      ],
    },
    {
      title: 'Metadata & Clinical Information',
      description: 'Patient clinicopathological features and genomic metadata.',
      files: [
        { name: 'metadata.cart.json', label: 'Metadata', type: 'JSON', icon: <FileTextOutlined /> },
        { name: 'clinical.cart.tar.gz', label: 'Clinical Information', type: 'TAR.GZ', icon: <FileZipOutlined /> },
      ],
    },
    {
      title: 'Analysis Results',
      description: 'Downstream bioinformatics analysis results including DEGs and Cox regression.',
      files: [
        { name: 'DEGs.csv', label: 'Differentially Expressed Genes', type: 'CSV', icon: <DatabaseOutlined /> },
        { name: 'Cox_results.csv', label: 'Univariate Cox Results', type: 'CSV', icon: <DatabaseOutlined /> },
      ],
    },
  ];

  const handleDownload = (fileName) => {
    // 触发下载逻辑：public文件夹下的文件直接通过根路径访问
    const link = document.createElement('a');
    link.href = `${process.env.PUBLIC_URL}/${fileName}`;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div style={{ padding: '40px', background: '#f0f2f5', minHeight: '80vh' }}>
      <div style={{ maxWidth: '1150px', margin: '0 auto' }}>
        <Card bordered={false} style={{ borderRadius: '15px', boxShadow: '0 8px 24px rgba(0,0,0,0.08)' }}>
          <Title level={2} style={{ textAlign: 'center', marginBottom: '10px' }}>Data Download Center</Title>
          <Paragraph type="secondary" style={{ textAlign: 'center', marginBottom: '40px' }}>
            Access and download the comprehensive datasets used in this LUAD study. 
            All files are provided for academic research purposes.
          </Paragraph>

          {downloadSections.map((section, index) => (
            <div key={index}>
              <Divider orientation="left" style={{ borderColor: '#d9d9d9' }}>
                <Text strong style={{ fontSize: '18px' }}>{section.title}</Text>
              </Divider>
              <Paragraph style={{ paddingLeft: '12px', color: '#666' }}>{section.description}</Paragraph>
              
              <List
                grid={{ gutter: 16, column: 2 }}
                dataSource={section.files}
                renderItem={(item) => (
                  <List.Item>
                    <Card size="small" hoverable style={{ borderRadius: '8px', border: '1px solid #e8e8e8' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Space size="middle">
                          <div style={{ fontSize: '24px', color: '#1890ff' }}>{item.icon}</div>
                          <div>
                            <div style={{ fontWeight: '600' }}>{item.label}</div>
                            <Tag color="blue">{item.type}</Tag>
                          </div>
                        </Space>
                        <Button 
                          type="primary" 
                          danger // 保持你偏好的危险/红色风格
                          shape="round" 
                          icon={<DownloadOutlined />} 
                          onClick={() => handleDownload(item.name)}
                        >
                          Download
                        </Button>
                      </div>
                    </Card>
                  </List.Item>
                )}
              />
              {index !== downloadSections.length - 1 && <div style={{ height: '20px' }} />}
            </div>
          ))}
        </Card>
      </div>
    </div>
  );
}